import type { EnteringAnimation, ExitingAnimation } from '@lmb-it/kitsconcerto-types';

/** Maps entering animation names to PrimeFlex CSS class names. */
export const enteringClassMap: Record<EnteringAnimation, string> = {
  fadeIn:       'fadein',
  fadeInUp:     'fadeinup',
  fadeInDown:   'fadeindown',
  fadeInLeft:   'fadeinleft',
  fadeInRight:  'fadeinright',
  slideInUp:    'slideup',
  slideInDown:  'slidedown',
  slideInLeft:  'fadeinleft',
  slideInRight: 'fadeinright',
  zoomIn:       'zoomin',
  zoomInUp:     'zoominup',
  zoomInDown:   'zoomindown',
  zoomInLeft:   'zoominleft',
  zoomInRight:  'zoominright',
  scaleIn:      'scalein',
  bounceIn:     'scalein',
  flip:         'flip',
  flipUp:       'flipup',
  flipLeft:     'flipleft',
  flipRight:    'flipright',
};

/** Maps exiting animation names to PrimeFlex CSS class names. */
export const exitingClassMap: Record<ExitingAnimation, string> = {
  fadeOut:       'fadeout',
  fadeOutUp:     'fadeoutup',
  fadeOutDown:   'fadeoutdown',
  fadeOutLeft:   'fadeoutleft',
  fadeOutRight:  'fadeoutright',
  slideOutUp:    'fadeoutup',
  slideOutDown:  'fadeoutdown',
  slideOutLeft:  'fadeoutleft',
  slideOutRight: 'fadeoutright',
  zoomOut:       'fadeout',
  bounceOut:     'fadeout',
};

/** Builds a combined animation class string from entering/exiting props. */
export function buildAnimationClasses(options: {
  entering?: EnteringAnimation;
  exiting?: ExitingAnimation;
}): string {
  const classes: string[] = [];
  if (options.entering) classes.push(enteringClassMap[options.entering]);
  if (options.exiting) classes.push(exitingClassMap[options.exiting]);
  return classes.join(' ');
}
